/*
 * GLOBAL ERROR HANDLER
 * ─────────────────────────────────────────────────────────────────
 * Receives execution failures from any workflow that sets:
 *   settings.errorWorkflow = '[SHARED] Global Error Handler'
 *
 * Enriches the error with context, applies severity triage,
 * then fans out to Slack, Google Sheets, and optionally PagerDuty.
 */

const execData = $input.first().json;

// ── Classify error severity ────────────────────────────────────────
const CRITICAL_WORKFLOWS = [
  'wf.etl-pipeline',
  'wf.crm-sync',
  'wf.lead-enrichment'
];

const workflowName  = execData.workflow?.name  || 'unknown';
const workflowId    = execData.workflow?.id    || 'unknown';
const executionId   = execData.execution?.id   || 'unknown';
const executionMode = execData.execution?.mode || 'unknown';
const errorMessage  = execData.execution?.error?.message || 'No error message';
const errorStack    = execData.execution?.error?.stack   || '';
const lastNode      = execData.execution?.lastNodeExecuted || 'unknown';
const startedAt     = execData.execution?.startedAt || new Date().toISOString();

const isCritical    = CRITICAL_WORKFLOWS.some(w => workflowName.includes(w));
const severity      = isCritical ? 'CRITICAL' : 'ERROR';

// ── Build error record ─────────────────────────────────────────────
const traceId = `err-${Date.now()}-${Math.random().toString(36).slice(2,8)}`;

const errorRecord = {
  traceId,
  severity,
  timestamp: new Date().toISOString(),
  workflow: {
    name: workflowName,
    id:   workflowId
  },
  execution: {
    id:        executionId,
    mode:      executionMode,
    startedAt,
    lastNode
  },
  error: {
    message: errorMessage,
    stack:   errorStack.slice(0, 1000)  // cap stack trace length
  },
  runbookUrl: `https://wiki.yourcompany.com/runbooks/${workflowName.replace(/\s+/g, '-').toLowerCase()}`,
  n8nUiUrl:   `${process.env.N8N_HOST || 'http://localhost:5678'}/workflow/${workflowId}/executions/${executionId}`
};

// ── Slack message (Block Kit) ──────────────────────────────────────
const severityEmoji = severity === 'CRITICAL' ? '🚨' : '🔴';

const slackBlocks = [
  {
    type: 'header',
    text: { type: 'plain_text', text: `${severityEmoji} Workflow Failure: ${workflowName}`, emoji: true }
  },
  {
    type: 'section',
    fields: [
      { type: 'mrkdwn', text: `*Severity:*\n${severity}` },
      { type: 'mrkdwn', text: `*Workflow:*\n${workflowName}` },
      { type: 'mrkdwn', text: `*Execution ID:*\n\`${executionId}\`` },
      { type: 'mrkdwn', text: `*Failed Node:*\n\`${lastNode}\`` },
      { type: 'mrkdwn', text: `*Mode:*\n${executionMode}` },
      { type: 'mrkdwn', text: `*Trace ID:*\n\`${traceId}\`` }
    ]
  },
  {
    type: 'section',
    text: { type: 'mrkdwn', text: `*Error:*\n\`\`\`${errorMessage.slice(0, 300)}\`\`\`` }
  },
  {
    type: 'actions',
    elements: [
      {
        type: 'button',
        style: 'danger',
        text: { type: 'plain_text', text: '🔍 View Execution' },
        url:  errorRecord.n8nUiUrl
      },
      {
        type: 'button',
        text: { type: 'plain_text', text: '📖 Runbook' },
        url:  errorRecord.runbookUrl
      }
    ]
  },
  { type: 'divider' }
];

return [{
  json: {
    errorRecord,
    slackChannel: isCritical ? '#oncall-alerts' : '#automation-errors',
    slackBlocks,
    slackText: `[${severity}] ${workflowName} failed at node \`${lastNode}\`: ${errorMessage.slice(0, 150)}`
  }
}];
